<?php namespace App\Http\Controllers; use App\Models\PreventiveMaintenance; class PreventiveMaintenanceController extends Controller{public function index(){return view('preventive-maintenance.index',['plans'=>PreventiveMaintenance::with('asset','technician')->orderBy('next_maintenance')->paginate(12)]);} public function show(PreventiveMaintenance $preventive_maintenance){return view('preventive-maintenance.show',['plan'=>$preventive_maintenance->load('asset','technician')]);}}
